void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var p = vector<vector<pii>>(2);
	var s = vector<int>(n + 1);
	fa(i, 1, n)s[i] = i;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return s[x];
		return s[x] = find(find, s[x]);
		};
	int cnt = n - 1;
	fa(i, 1, m) {
		int u, v, w; cin >> u >> v >> w;
		p[w].pb({ u,v });
		int e1 = find(find, u), e2 = find(find, v);
		if (e1 != e2)s[e2] = e1, cnt--;
	}
	if (cnt) {
		cout << 0 << endl;
		return;
	}
	var f = [&](int x, int y)->pii {
		fa(i, 1, n)s[i] = i;
		int cnt = n - 1;
		int cntx = 0, cnty = 0;
		for (const var& [u, v] : p[x]) {
			int e1 = find(find, u), e2 = find(find, v);
			if (e1 != e2)s[e2] = e1, cnt--, cntx++;
			if (cnt == 0)break;
		}
		for (const var& [u, v] : p[y]) {
			int e1 = find(find, u), e2 = find(find, v);
			if (e1 != e2)s[e2] = e1, cnt--, cnty++;
			if (cnt == 0)break;
		}
		return { cntx,cnty };
		};
	var x = f(0, 1), y = f(1, 0);
	cout << x.px - y.py + 1 << endl;
	return;
}
